import{_ as a,c as e,o,aj as i,j as r}from"./chunks/framework.CLcCQpUA.js";const f=JSON.parse('{"title":"❓ 常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq/index.md","filePath":"faq/index.md"}'),t={name:"faq/index.md"},s=i('<h1 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h1><h2 id="_1-gui" tabindex="-1">1. GUI <a class="header-anchor" href="#_1-gui" aria-label="Permalink to &quot;1. GUI&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">鉴于还是有人不看快速开始，再次声明启动出现各种异常的万恶之源！</p><p>⚠️ 解压路径不能含有中文/中标 ⚠️⚠️⚠️⚠️⚠️⚠️⚠️⚠️⚠️⚠️</p></div><h3 id="预览窗口页面显示异常-页面空白-图片加载等" tabindex="-1">预览窗口页面显示异常/页面空白/图片加载等 <a class="header-anchor" href="#预览窗口页面显示异常-页面空白-图片加载等" aria-label="Permalink to &quot;预览窗口页面显示异常/页面空白/图片加载等&quot;">​</a></h3><p>刷新一下页面<br> 有些是 JavaScript 没加载，有些是对方服务器问题</p><h3 id="pypi换源指引" tabindex="-1">pypi换源指引 <a class="header-anchor" href="#pypi换源指引" aria-label="Permalink to &quot;pypi换源指引&quot;">​</a></h3><p>先选出当前网络环境能打开的（<a href="https://pypi.tuna.tsinghua.edu.cn/simple/" target="_blank" rel="noreferrer">清华源</a> / <a href="https://mirrors.aliyun.com/pypi/simple/" target="_blank" rel="noreferrer">阿里源</a> / <a href="https://repo.huaweicloud.com/repository/pypi/simple/" target="_blank" rel="noreferrer">华为源</a>，网址后缀加上 comicguispider 检测 ）</p><div class="warning custom-block"><p class="custom-block-title">不限以下两种，所有文档的所有涉及pypi源命令因网络问题出错的都是更换源网址这样去处理</p></div><h4 id="i-绿色包部署换源" tabindex="-1">Ⅰ. 绿色包部署换源 <a class="header-anchor" href="#i-绿色包部署换源" aria-label="Permalink to &quot;Ⅰ. 绿色包部署换源&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">默认是清华源，以下是切换至阿里源命令示例，在解压目录开终端</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\CGS.exe </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">i https://mirrors.aliyun.com/pypi/simple</span></span></code></pre></div></div><h4 id="ii-cgs更新-脚本集-kemono-额外依赖换源" tabindex="-1">Ⅱ. CGS更新/脚本集(kemono)额外依赖换源 <a class="header-anchor" href="#ii-cgs更新-脚本集-kemono-额外依赖换源" aria-label="Permalink to &quot;Ⅱ. CGS更新/脚本集(kemono)额外依赖换源&quot;">​</a></h4><p>默认使用清华源，换源通过 <a href="/ComicGUISpider/config/#pypi源-pypi-source">配置窗口点选更换</a></p><h2 id="_2-爬虫" tabindex="-1">2. 爬虫 <a class="header-anchor" href="#_2-爬虫" aria-label="Permalink to &quot;2. 爬虫&quot;">​</a></h2><h3 id="jm的章节下载" tabindex="-1">jm的章节下载 <a class="header-anchor" href="#jm的章节下载" aria-label="Permalink to &quot;jm的章节下载&quot;">​</a></h3><p>仅能在 <a href="/ComicGUISpider/feat/clip.html">📋读剪贴板</a> 流程中使用，点进去看相关教程</p><h3 id="拷贝漫画部分无法出列表" tabindex="-1">拷贝漫画部分无法出列表 <a class="header-anchor" href="#拷贝漫画部分无法出列表" aria-label="Permalink to &quot;拷贝漫画部分无法出列表&quot;">​</a></h3><p>拷贝有些漫画卷和话是分开的，api结构转换的当前是有结果的，但没解析，如需前往群里反馈</p><h3 id="拷贝-mangabz多选书情况" tabindex="-1">拷贝/Māngabz多选书情况 <a class="header-anchor" href="#拷贝-mangabz多选书情况" aria-label="Permalink to &quot;拷贝/Māngabz多选书情况&quot;">​</a></h3><p>多选书时，在章节序号输入时可直接点击<code>开始爬取</code>跳过当前书的章节选择，只要出进度条即可</p><h2 id="_3-其他" tabindex="-1">3. 其他 <a class="header-anchor" href="#_3-其他" aria-label="Permalink to &quot;3. 其他&quot;">​</a></h2><h3 id="modulenotfounderror-no-module-named-xxx" tabindex="-1">ModuleNotFoundError: No module named &#39;xxx&#39; <a class="header-anchor" href="#modulenotfounderror-no-module-named-xxx" aria-label="Permalink to &quot;ModuleNotFoundError: No module named &#39;xxx&#39;&quot;">​</a></h3><p>截图或带上 <code>log</code> 提交 <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=bug-report.yml" target="_blank" rel="noreferrer">issue</a></p><h3 id="更新失败后程序无法打开" tabindex="-1">更新失败后程序无法打开 <a class="header-anchor" href="#更新失败后程序无法打开" aria-label="Permalink to &quot;更新失败后程序无法打开&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">两种方式可选</p><ul><li>删干净原目录/换一个解压目录 并重新解压📦绿色包，然后重新初始化部署/更新</li><li>干脆直接使用 <a href="/ComicGUISpider/deploy/quick-start.html#1-下载--部署">uv tool方式部署安装</a></li></ul></div><hr><div class="warning custom-block"><p class="custom-block-title">如果存在上述没有覆盖的问题</p><p>请带上 <code>log</code> 到 <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=bug-report.yml" target="_blank" rel="noreferrer">issue</a> 反馈 或 进群(右上角qq/discord)反馈。</p></div>',26),l=r("iframe",{src:"https://discord.com/widget?id=1373740034536112138&theme=dark",width:"350",height:"500",allowtransparency:"true",frameborder:"0",sandbox:"allow-popups allow-popups-to-escape-sandbox allow-same-origin allow-scripts"},null,-1),n=[s,l];function d(c,p,h,u,m,b){return o(),e("div",null,n)}const _=a(t,[["render",d]]);export{f as __pageData,_ as default};
